from collections import Counter

class Solution(object):
    def maximumLength(self, s):
        n = len(s)
        # Count all special substrings
        freq = Counter()
        for i in range(n):
            for j in range(i+1, n+1):
                sub = s[i:j]
                if len(set(sub)) == 1:
                    freq[sub] += 1
        ans = -1
        for sub, cnt in freq.items():
            if cnt >= 3:
                ans = max(ans, len(sub))
        return ans
